const t={INTRO:{title:"The Request",lines:[{speaker:"Delphine",text:"I have a map of the plantation and I am only aware of the study as a location so far.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"I have been provided with photos of everyone who was known to be present on the premises at the time.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"but I only have the name of my benefactor's father and sister. I will need to figure out the names of the other guests before I can start being able to connect with them.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Right. Let's go to the study and see what we can find.",portrait:"portraits/investigator.png"}]},STUDY_ZERO:{title:"Anchored Memories",lines:[{speaker:"Delphine",text:"I can feel the essence of the study as I focus on it. It's nearly as if I am in the room. The feeling is impossible to describe and many think it's not real and just a parlour trick. I don't blame them.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"There's a specific feel to old rooms. The objects that form the essence of the space become part of the room. Items that remain in that space long enough become anchored to the space itself.",portrait:"portraits/investigator.png"}]},PHONE_TIP:{title:"Infused items",lines:[{speaker:" ",text:"Delphine can focus on items, like the telephone here."},{speaker:" ",text:"You can go to the phone on the items screen in the inventory (or press i anywhere) and attune it by attributing the correct owner to it."},{speaker:" ",text:"Once the owner has been identified, Delphine can feel the aura of the person using the item at any given time and see the echo of what happened in its presence."},{speaker:"Delphine",text:"Given that Jeremiah is the owner of the plantation, it is likely that he is the one who uses the telephone most often and therefore it is likely to be him that I need to attune it to.",portrait:"portraits/investigator.png"}]},LINES:{lines:[{speaker:"Delphine",text:"A temporary military camp would have been referred to as the lines. It would have consisted of huts made of local materials instead of tents.",portrait:"portraits/investigator.png"}]},STUDY_ONE:{title:"Echoes of the Study",lines:[{speaker:"Delphine",text:"I know that Jeremiah was alone at 4pm in the study. If I focus hard enough on Jeremiah, I should be able to see the echo of what happened there.",portrait:"portraits/investigator.png"},{speaker:" ",text:"Set the timeline to 16:00 and place Jeremiah's photo into focus."},{speaker:" ",text:"A guest can only be in one location at any given time. If you see a guest in a location, they cannot be in another location at the same time."},{speaker:" ",text:"an event doesn't necessarily take the whole hour but only one significant event can happen at a location at a time."},{speaker:" ",text:"Guests may appear in the edges of an echo in one room and be in another room for the remainder of the hour. They will only count in the room where they are fully present."}]},LIBRARY_WARNING:{title:"Missing Evidence",lines:[{speaker:"Delphine",text:"I don't have enough evidence to discover anything in the library yet. I should focus on the arrival of the unexpected guest for now.",portrait:"portraits/investigator.png"}]},STUDY_11:{title:"The Telephone Call",branches:[{check:e=>!e.unlockedPeople.has("p10")&&!e.unlockedPeople.has("p9"),lines:[{speaker:"Delphine",text:"There is a person named Jiro in the room alongside the person making the phone call. I should come back here once I've figured out who they both are to see the whole of this conversation.",portrait:"portraits/investigator.png"}]},{check:e=>!e.unlockedPeople.has("p10"),lines:[{speaker:"Delphine",text:"There is a person named Jiro in the room alongside Kanan. I should come back here once I've figured out who he is to see his side of this conversation.",portrait:"portraits/investigator.png"}]},{check:e=>e.unlockedPeople.has("p10"),lines:[{speaker:"Delphine",text:"I now know that both Jiro and Kanan were in the study here, I can unlock the full echo by focusing on both of them.",portrait:"portraits/investigator.png"}]}]},STUDY_11_2:{title:"The Telephone Call",lines:[{speaker:"Delphine",text:"There is a person named Jiro in the room alongside Kanan. I should come back here once I've figured out who he is to see his side of this conversation.",portrait:"portraits/investigator.png"}]},DEDUCTION_HELP:{title:"A New Strategy",lines:[{speaker:"Delphine",text:"I now have the names of two of the guests. I need to remember that indigenous people to Borneo often do not have a surname so I should be able to identify Kanan with just his first name.",portrait:"portraits/investigator.png"},{speaker:" ",text:"If Delphine can figure out who they are based on the context, she can assign a name to their face in the Guests case file."}]},TELEPHONE_0:{title:"Hand-cranked Telephone",lines:[{speaker:"Delphine",text:"The telephone has some strong energy. I can feel it being used quite clearly at 2am by a man with a local accent.",portrait:"portraits/investigator.png"},{speaker:" ",text:"Now that Delphine has aura attached to the telephone, she can feel whoever is using it at any time."},{speaker:" ",text:"But she is only able to hear and feel the person using or holding the item and not anyone else in the room."}]},GHOST_IMAGE:{title:"The Ghost Image",lines:[{speaker:"Delphine",text:"Good lord! That flash... that image in the mirror...",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"It was faint, but the psychic imprint is undeniable.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"The sheer intensity of the flash left a mark on the ether. It's strong enough.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"With this anchor, I can track him. I can feel his movements through the plantation now.",portrait:"portraits/investigator.png"}]},SHAMAN_NAME:{title:"The Shaman",lines:[{speaker:"Delphine",text:"Babalian Antau... A powerful Shaman.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"I doubt I will be able to find a photo of him. He is too obscure, too hidden in the shadows of history.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"I will have to deduce his presence by other means. I will need to think outside of the box if I want to be able to piece together his movements.",portrait:"portraits/investigator.png"}]},TUAN_BESAR:{title:"The Tuan",theme:"british_standards",lines:[{speaker:"Delphine",text:"In these plantations, 'Tuan' is the standard address for officials. 'Tuan Besar', or the 'Big Master', is the head manager in charge of the entire estate. In this case Kanan is referring to Jeremiah Goodwill.",portrait:"portraits/investigator.png"}]},MEM:{title:"The Mem",theme:"british_standards",lines:[{speaker:"Delphine",text:"Mem is a specific title for the 'Lady of the House'. I gather that Little Mem is an affectionate term used by the servants to refer to Lune.",portrait:"portraits/investigator.png"}]},CONSTABULARY:{title:"The Constabulary",theme:"maritime_rules",lines:[{speaker:"Delphine",text:"The Marine Wing of the North Borneo Armed Constabulary is the closest thing to a coast guard in the British parts of North Borneo. They operated small, armed motor launches that patrolled the coasts before the Japanese invasion.",portrait:"portraits/investigator.png"}]},PIRACY_GRILLE:{theme:"piracy",title:"The Grille",lines:[{speaker:"Delphine",text:"The threat of a Pirate hijack was so common that steamships in the 1920s were equipped with piracy grilles, heavy iron bars and gates that separated the bridge and first-class quarters from the rest of the ship, essentially turning the officers' area into a fortress",portrait:"portraits/investigator.png"}]},GAYUNG:{title:"Gayung",theme:"british_standards",lines:[{speaker:"Delphine",text:"A Gayung is a traditional plastic or metal ladle used for scooping water from a jar or bucket for bathing.",portrait:"portraits/investigator.png"}]},SHANGAI_JAR:{title:"Shanghai Jar",theme:"british_standards",lines:[{speaker:"Delphine",text:"Large ceramic Shanghai Jars are commonly used in colonial houses to store cool water for bathing in the tropical heat.",portrait:"portraits/investigator.png"}]},FEVER:{title:"The Fever",theme:"tropical_killers",lines:[{speaker:"Delphine",text:"Lune must mean the Blackwater fever, by far the most feared cause of death for young Europeans in the tropics. It's a terrifying complication of repeated Malaria infections and fatal within days.",portrait:"portraits/investigator.png"}]},STARCHED_WHITES:{title:"Starched Whites",theme:"british_standards",lines:[{speaker:"Delphine",text:"Starched whites are the standard attire for men in colonial houses. Starched white shorts, white knee-high socks, and a white shirt, they are clean and pressed and strongly fraganced. They are not practical for work, but are used to maintain an ill-conceived illusion of British superiority.",portrait:"portraits/investigator.png"}]},SABAH:{title:"Sabah",theme:"colonies",lines:[{speaker:"Delphine",text:"Sabah is the largest state of Borneo. It is bordered by the states of Sarawak and Kalimantan to the west, and the Philippines to the east. It's ruled by the British North Borneo Chartered Company, a private company that was granted a royal charter by the British government back in the 19th century.",portrait:"portraits/investigator.png"}]},SUNDOWNER:{title:"Sundowner",theme:"culture",lines:[{speaker:"Delphine",text:"My research shows that a Sundowner is local colloquialism for an evening drink taken when the sun is setting to mark the transition from the heat of the day to the cool of the evening.",portrait:"portraits/investigator.png"}]},GIN_PAHITS:{title:"Gin Pahits",theme:"culture",lines:[{speaker:"Delphine",text:"Gin Pahits is a gin mixed with several heavy dashes of Angostura bitters which helps settle the stomach after a day in the humid jungle.",portrait:"portraits/investigator.png"}]},SMALL_CHOPS:{title:"Small Chops",theme:"culture",lines:[{speaker:"Delphine",text:"Small Chops is a local term for snacks to serve with Sundowners. They're designed to be salty and pungent to stimulate the palate and encourage drinking.",portrait:"portraits/investigator.png"}]},TOBACCO_TRADE_IS_DRYING_UP:{title:"The Tobacco Trade is Drying Up",theme:"colonies",lines:[{speaker:"Delphine",text:"30 years ago, North Borneo was world-famous for its high-quality cigar wrapper leaf. However, by the 1930s, many tobacco companies began to wind up or switch to rubber and coconut because of cigarettes becoming more fashionable and soil exhaustion. It looks like the Goodwill were behind the curve and feeling the pressure.",portrait:"portraits/investigator.png"}]},BAJAU:{title:"The Bajau",theme:"pearls",lines:[{speaker:"Delphine",text:"The Bajau are a nomadic sea people who live in the waters around Borneo. They are amazing divers and experts on pearls. ",portrait:"portraits/investigator.png"}]},TOWKAY:{title:"The Towkays",theme:"pearls",lines:[{speaker:"Delphine",text:"The Chinese Towkays are powerful and influential merchants who controlled the pearl trade in North Borneo before the war. ",portrait:"portraits/investigator.png"}]},KORNBRAND:{title:"Kornbrand",theme:"culture",lines:[{speaker:"Delphine",text:"Kornbrand is a German brand of grain spirit very similar to vodka but often distilled to a slightly lower proof to retain the flavor of the grain. To a British observer, it might look like vodka, but to a German or Russian, the distinction is vital. ",portrait:"portraits/investigator.png"}]},SUNNING:{title:"The Sunning",theme:"piracy",lines:[{speaker:"Delphine",text:"The Sunning was a steamship that was hijacked by pirates in 1926.",portrait:"portraits/investigator.png"}]},TUAN_DOSE:{title:"Tuan's Dose",theme:"tropical_killers",lines:[{speaker:"Delphine",text:"A dose of Qunine taken daily by the masters of the plantation (the Tuans). Quinine was usually taken daily with the Sundowner and an evening snack as it was believed it shouldn't be taken on an empty stomach. Almost everyone in Borneo take it everyday to fight off Malaria.",portrait:"portraits/investigator.png"}]},QUININE:{title:"Quinine",theme:"tropical_killers",lines:[{speaker:"Delphine",text:"Quinine was usually taken daily with the Sundowner and an evening snack as it was believed it shouldn't be taken on an empty stomach. Almost everyone in Borneo take it everyday to fight off Malaria.",portrait:"portraits/investigator.png"}]},SALLOW:{title:"Sallow",theme:"tropical_killers",lines:[{speaker:"Delphine",text:"Sallow is a term used to describe the yellowish skin that develops on the face and hands of Europeans who contracted malaria. It is a sign of chronic illness.",portrait:"portraits/investigator.png"}]},BIAS_BAY:{title:"Bias Bay",theme:"piracy",lines:[{speaker:"Delphine",text:"Bias Bay is a hidden cove by the coast of Guangdong, it served as a pirate republic during the piracy golden age.",portrait:"portraits/investigator.png"}]},STRAITS_STEAMSHIP:{title:"The Straits Steamship",theme:"the_seas",lines:[{speaker:"Delphine",text:"The Straits Steamship was the main route for the Goodwill to transport goods and people from the mainland to Borneo. It was a regular route, but it was also a target for pirates.",portrait:"portraits/investigator.png"}]},SANDAKAN:{title:"Sandakan",theme:"colonies",lines:[{speaker:"Delphine",text:"Sandakan was the capital of British North Borneo and the largest city in the region. It was completely destroyed by the end of the war.",portrait:"portraits/investigator.png"}]},KACHANG:{theme:"culture",lines:[{speaker:"Delphine",text:"Kachang means 'bean' or 'nut' in Malay. Usually peanuts roasted with spices.",portrait:"portraits/investigator.png"}]},BLACK_SMOKE:{theme:"japanese_invasion",lines:[{speaker:"Delphine",text:"When the Japanese invasion was imminent, the Dutch blew up the oil refineries and set the wells at Miri and Balikpapan on fire. For weeks, the sky over Borneo was stained black.",portrait:"portraits/investigator.png"}]},CHANDU:{theme:"opium",lines:[{speaker:"Delphine",text:"Chandu is refined opium, boiled and fermented into a treacle-like paste. It was a government monopoly in many colonies.",portrait:"portraits/investigator.png"}]},DROSS:{theme:"opium",lines:[{speaker:"Delphine",text:"Dross is the charcoal-like toxic residue left after smoking opium. It's often scraped out and re-mixed with fresh opium or consumed by addicts who can't afford refined Chandu.",portrait:"portraits/investigator.png"}]},LAMP:{lines:[{speaker:"Delphine",text:"A Tilley Lamp, the standard pressure paraffin lamp of the British colonies.",portrait:"portraits/investigator.png"}]},KOTA_BHARU:{title:"Kota Bharu",lines:[{speaker:"Delphine",text:"Kota Bharu, in northeast Malaya, was a crucial military hotspot and the site of the first major battle of the Pacific War.",portrait:"portraits/investigator.png"}]},RUNDUM_REBELLION:{title:"The Rundum Rebellion",theme:"colonies",lines:[{speaker:"Delphine",text:"The Rundum Rebellion of 1915 was the last major uprising of the Murut people against the British North Borneo Chartered Company. It was sparked by the Company's tax policies and forced labor.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"The Muruts, famous for their blowpipes, built intricate underground forts in the jungles, making them invisible.",portrait:"portraits/investigator.png"}]},TUJU:{title:"The Tuju",theme:"occult",lines:[{speaker:"Delphine",text:"The Tuju is a curse where a shaman, the Bomoh, magically sends an object into a victim's body to kill them.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"The victim suffers sudden, unexplained agony and Western medicine finds nothing wrong.",portrait:"portraits/investigator.png"}]},AISYAH_NAME:{title:"The Servant Girl",lines:[{speaker:"Delphine",text:"Aisyah must be a local servant girl. There is only one in my pile of photos. I'll assume it's her and identify her now.",portrait:"portraits/investigator.png",action:"unlock_p11"}]},PIRATE_CAPTAIN:{title:"The Pirate Captain",lines:[{speaker:"Delphine",text:"(Thinking) That man... Ludwig Harrow. He carries himself like a king, not a common bandit. Is he infamous enough to be in the papers?",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"(Thinking) I need to call Armand about the distress call on the phone anyway. I'll ask him to check the archives for Captain Harrow as well.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"(On Phone) Armand? It's Delphine. Listen carefully. I have a phonetic transcription of a call made from the plantation in Malay. I was wondering if you could translate?",portrait:"portraits/investigator.png"},{speaker:"Armand",text:'(Over Phone) Delphine... *sigh*. My Malay is rusty, but "mati" means dead. It sounds like he was claiming Jeremiah Goodwill was murdered by pirates and requested immediate assistance from the British Navy. They were due to have arrived by 09:00 the next morning.',portrait:"portraits/armand.jpeg"},{speaker:"Delphine",text:"He lied and painted a picture of a massacre to ensure they would hurry.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"I have another request while I have you. It's going to sound very strange but bear with me. The plantation was attacked by pirates. The leader of these pirates was a man named Ludwig Harrow. I was hoping beyond hope that there might be some information about him somewhere.",portrait:"portraits/investigator.png"},{speaker:"Armand",text:"(Over Phone) Harrow? Startling. He is a legend, Delphine. Not for piracy, but for the war. He led a guerrilla unit against the Japanese occupation. Saved hundreds from the Sandakan Death Marches.",portrait:"portraits/armand.jpeg"},{speaker:"Armand",text:"(Over Phone) He is a hero in the history books. I have his service photo from the archives. I will send it over to you.",portrait:"portraits/armand.jpeg",action:"unlock_p13"},{speaker:"Delphine",text:"That's incredible. Thank you so much Armand.",portrait:"portraits/investigator.png"}]},EPILOGUE:{title:"Closed Case",lines:[{speaker:"Delphine",text:"I have uncovered the truth.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"My benefactor's sister, Lune wasn't lost to the flames. She survived that night. She escaped the plantation and I am hoping she found a new life here in England.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"I can provide him this information but I believe there is still much to be uncovered.",portrait:"portraits/investigator.png",action:"credits"}]},IRON_ROAD:{title:"The Iron Road",theme:"colonies",lines:[{speaker:"Delphine",text:"The North Borneo Railway was a uniquely British project. It was the only railway system on the entire island. Plantations along the coast were designed to plug into this rail line. The railway was also used to transport goods to and from the port of Sandakan.",portrait:"portraits/investigator.png"}]},BROOKE_RAJAHS:{title:"The Brooke Rajahs",theme:"colonies",lines:[{speaker:"Delphine",text:"The British part of Borneo was divided into three territories: Sarawak which was ruled by the Brooke family, known as the White Rajahs, British North Borneo which was ruled by the British North Borneo Chartered Company, and Brunei which was a British protectorate where the Sultan still ruled.",portrait:"portraits/investigator.png"}]},HALE_ROCKETS:{title:"The Hale Rockets",theme:"japanese_invasion",lines:[{speaker:"Delphine",text:"The Hale Rockets were a series of rockets developed by the British. They were designed to be launched from the ground.",portrait:"portraits/investigator.png"}]},TRIAD:{title:"The Triad",theme:"opium",lines:[{speaker:"Delphine",text:"The Chinese Triad was a highly organized, criminal empire in Borneo and managed the island's illicit economy.",portrait:"portraits/investigator.png"}]},BOMOH:{title:"The Bomoh",theme:"occult",lines:[{speaker:"Delphine",text:"The Bomoh was the spiritual and medicinal Bornean Shaman. They were highly respected and were often called upon to treat the sick and injured as well as to perform more spiritual rituals.",portrait:"portraits/investigator.png"}]},JOURNEY_INTRO:{title:"The Vision Strengthens",lines:[{speaker:"Delphine",text:"The web of memories is complete. I can feel the resonance strengthening... it's pulling me beyond the island.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Lucas, Lune, and Rose... I can see their escape. They endured a long, harrowing journey back to England.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"I've unlocked a new pathway. It maps their return voyage. I can now follow them across the sea.",portrait:"portraits/investigator.png"}]},COLLYER_QUAY:{title:"Collyer Quay",lines:[{speaker:"Delphine",text:"Collyer Quay is a bustling area in Singapore. It is a hub for trade and commerce. The streets are lined with shops and markets.",portrait:"portraits/investigator.png"}]},SAILORS_HOME:{title:"Sailors Home",lines:[{speaker:"Delphine",text:"Sailors Home ",portrait:"portraits/investigator.png"}]},BOLSTER:{title:"Bolster",lines:[{speaker:"Delphine",text:"Long, firm pillows common in the tropics.",portrait:"portraits/investigator.png"}]},ULU:{title:"The Ulu",lines:[{speaker:"Delphine",text:"The Ulu is a dense rainforest in Borneo.",portrait:"portraits/investigator.png"}]},CAUSEWAY:{title:"The Causeway",lines:[{speaker:"Delphine",text:"The Causeway is a bridge connecting Singapore to Malaysia.",portrait:"portraits/investigator.png"}]},DBS:{title:"DBS",lines:[{speaker:"Delphine",text:"Distressed British Subject (DBS): the official category for British refugees with no means of support fleeing the Japanese occupation.",portrait:"portraits/investigator.png"}]},MALACCA:{title:"Malacca",lines:[{speaker:"Delphine",text:"Long, narrow stretch of water that separates the Malay Peninsula from the Indonesian island of Sumatra.",portrait:"portraits/investigator.png"}]},IPOH:{title:"Ipoh",lines:[{speaker:"Delphine",text:"A major city in Malaya that fell early during the invasion.",portrait:"portraits/investigator.png"}]},KEDAH:{title:"Kedah",lines:[{speaker:"Delphine",text:"Kedah is a state located in the northwestern part of Peninsular Malaysia, bordering Thailand. In late December 1941, Kedah was the site of a strategic disaster for the British. It was the first region of the Malayan mainland to be invaded by the Japanese (on December 8th, just hours after Pearl Harbor).",portrait:"portraits/investigator.png"}]},BETTY:{title:"Betty",lines:[{speaker:"Delphine",text:"The Allied reporting names for the Japanese twin-engine bombers that patrolled the Malacca Strait.",portrait:"portraits/investigator.png"}]},GALLEFACE:{title:"The Galle Face",lines:[{speaker:"Delphine",text:"The Galle Face was the most prestigious and evocative landmark in Colombo, Ceylon. It consisted of two main parts: the Galle Face Green (a vast seaside promenade) and the iconic Galle Face Hotel.",portrait:"portraits/investigator.png"}]},DUFF:{title:"Duff",lines:[{speaker:"Delphine",text:"Duff is slang for christmas pudding.",portrait:"portraits/investigator.png"}]},JAGA:{title:"Jaga",lines:[{speaker:"Delphine",text:"A jaga is a Guard. Sikh or Punjabi men were commonly employed as watchmen across British Borneo, typically wearing formal turbans and high-collared buttoned tunics.",portrait:"portraits/investigator.png"}]},FIFTH_COLUMN:{title:"The Fifth Column",theme:"japanese_invasion",lines:[{speaker:"Delphine",text:"The Fifth Column was the name given to the Axis powers' espionage and sabotage activities in the Allied countries during World War II. It was a term coined by Winston Churchill to describe the Axis powers' efforts to undermine the morale and effectiveness of the Allied forces.",portrait:"portraits/investigator.png"}]},SIS:{title:"SIS",lines:[{speaker:"Delphine",text:"The Secret Intelligence Service (SIS) was the United Kingdom's first intelligence agency. It was founded in 1909 and was responsible for gathering intelligence on foreign powers, particularly Germany and the Soviet Union and monitoring the Fifth Column. It was later renamed MI6.",portrait:"portraits/investigator.png"}]},SECRETARIAT:{title:"Colonial Secretariat",lines:[{speaker:"Delphine",text:"The civil servants managing the government on behalf of the Governor. It was the final authority for exit visas, travel permits, and emergency funds for refugees.",portrait:"portraits/investigator.png"}]},SUMATRA:{title:"Sumatra",lines:[{speaker:"Delphine",text:"Sumatra is the largest island in Indonesia. It was the crown jewel of the Dutch East Indies and the primary reason Japan went to war in the Pacific.",portrait:"portraits/investigator.png"}]},STUKAS:{title:"Stukas",lines:[{speaker:"Delphine",text:"Stukas refer to the Junkers Ju 87, a famous German dive-bomber and ground-attack aircraft used by the Luftwaffe in World War II.",portrait:"portraits/investigator.png"}]},TRAMP_STEAMER:{title:"Tramp Steamers",lines:[{speaker:"Delphine",text:"The tramp steamer was a boat that wandered from port to port in search of leftover cargo to sell.",portrait:"portraits/investigator.png"}]},SHOPHOUSE:{title:"Shop Houses",lines:[{speaker:"Delphine",text:"The shophouses were two-story terrace houses with shops on the ground floor and living spaces above. By 1941, these buildings had become labyrinths of small interior cubicles separated by thin plywood partitions to cram as many refugees waiting for a way out as possible .",portrait:"portraits/investigator.png"}]},ENDING_INTRO:{title:"The Final Threshold",lines:[{speaker:"Rose",text:"Good afternoon. How may I help you?",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"Mrs Sterling? It's so good to finally meet you.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"You don't know me but I know a lot about you and your family and I would love to come in and explain.",portrait:"portraits/investigator.png"},{speaker:"Rose",text:"Come in, come in. Please don't mind the mess, I was in the middle of scoring tests. I'm a school teacher you see.",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"Thank you very much.",portrait:"portraits/investigator.png"},{speaker:"Rose",text:"Lune, we have company!",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Lune",text:"Coming!",portrait:"portraits/lune_older.png"},{speaker:"Delphine",text:"Lune! Look at you! You are such a beautiful young woman.",portrait:"portraits/investigator.png"},{speaker:"Lune",text:"Excuse me? Do I know you?",portrait:"portraits/lune_older.png"},{speaker:"Delphine",text:"It's a long story. Is Mr. Sterling around? I would very much like all of you to be here before I explain my sudden visit.",portrait:"portraits/investigator.png"},{speaker:"Rose",text:"I'm so sorry. My husband is still at work. He shan't be long.",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"Well I suppose I could start. The main person I'm here to see is in this room.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Lune, there is something very important I must tell you.",portrait:"portraits/investigator.png",action:"show_ending_choice"}]},ENDING_1:{title:"The Truth Revealed",lines:[{speaker:"Delphine",text:"Your brother. Your actual brother is alive... Miss Goodwill.",portrait:"portraits/investigator.png"},{speaker:"Lune",text:"What? What... What are you saying? How do you know my?... That's not possible.",portrait:"portraits/lune_older.png"},{speaker:"Rose",text:"Who are you? Why are you saying these horrible things? We've suffered and grieved enough!",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"I'm sorry. I'm truly sorry. This must come as a shock but I... I have proof. Here, read this letter.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"I'm a... Sensitive. I can see echoes of the past and your brother hired me to find out what had happened to you and your father, Lune. He thought you had both perished that night in Borneo or he would have looked for you closer to home. ",portrait:"portraits/investigator.png"},{speaker:"Lune",text:"But Lucas said...",portrait:"portraits/lune_older.png"},{speaker:"Delphine",text:"He lied to you Lune. He lied to both of you. I don't know why but he hid this truth from you these past few years.",portrait:"portraits/investigator.png"},{speaker:" ",text:"Lucas enters the house."},{speaker:"Lucas",text:"What... What's going on?",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:" ",text:"Rose throws the letter at Lucas."},{speaker:"Rose",text:"When were you going to tell us? Or were you never going to tell us? How could you do this to her?",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:" ",text:"Lucas reads the letter."},{speaker:"Lucas",text:"I'm... I'm so sorry. I didn't want to lose you. I didn't want to lose this. I love you. I love you both so much.",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"Lune",text:"I don't understand. How could you say you love me but break my heart so badly? You saw what it did to me to lose my father and my mother and then you decided it would be okay to kill my brother too?",portrait:"portraits/lune_older.png"},{speaker:"Lucas",text:"I was so scared of losing you. He's your actual brother! And he's successful, rich and... I'm nothing. I don't deserve either of you.",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"Rose",text:"And what about me? What about us? What did you think it would do to us?",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Lucas",text:"I just don't understand why you love me Rose. I keep expecting you to come to your senses and leave me. And if Lune wasn't around, I feared you would have done so already. I fear you are only with me because it's convenient. You could do so much better than me.",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"Rose",text:"You are insane. I would have chosen you Lucas. In a hundred rooms, in a hundred lives, I would have chosen you. I loved you.",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Rose",text:"But now...",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Rose",text:"Delphine. Can you take us to see Lune's brother?... Right away?",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"Yes of course.",portrait:"portraits/investigator.png"},{speaker:"Rose",text:"Lune?",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Lune",text:"I loved you so much. I loved our family so much. You have broken my heart Lucas. I hope you're happy.",portrait:"portraits/lune_older.png"},{speaker:" ",text:"Lune rips the necklace from her neck. Pearls go flying across the room."},{speaker:"Lune",text:"I'm ready.",portrait:"portraits/lune_older.png"},{speaker:"Delphine",text:"Let us depart. He's waiting for us at a cafe not far from here.",portrait:"portraits/investigator.png"},{speaker:" ",text:"Lucas doesn't say a word as he watches them leave. He just stands there weeping uncontrollably."},{speaker:" ",text:"The end. ",action:"credits"}]},ENDING_2:{title:"A Message from Beyond",lines:[{speaker:"Delphine",text:"Lune, this is going to sound insane but I'm what they call a Sensitive.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"I can sense echoes from the past and souls that have not yet departed this world. Ghosts if you will.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Your brother... Your actual brother Miss Goodwill. He contacted me... ",portrait:"portraits/investigator.png"},{speaker:"Lune",text:"What? What... What are you saying? How do you know my?... That's not possible.",portrait:"portraits/lune_older.png"},{speaker:"Delphine",text:"From beyond the grave. His soul could not rest until he understood what had happened to you.",portrait:"portraits/investigator.png"},{speaker:"Rose",text:"Who are you? Why are you saying these horrible things? We've suffered and grieved enough!",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"I'm sorry. I'm truly sorry. This must come as a shock and I... I have no proof save for this journal I wrote describing everything that has happened to you since that fateful night in Borneo.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"How could I know all this if I didn't have the powers I am claiming?",portrait:"portraits/investigator.png"},{speaker:" ",text:"Rose and Lune flip through the journal, their face white with shock as they read their life."},{speaker:"Rose",text:"I just can't get my head around this. How did he contact you?",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"I thought I received a letter but it wasn't actually quite real. In a way I should have known. It came with photos of everyone in the plantation at the time. I mean how would he have got hold of pictures of Kanan and Aisyah for example?...",portrait:"portraits/investigator.png"},{speaker:" ",text:"Rose and Lune are staring at Delphine incredulously."},{speaker:"Delphine",text:"I know how it sounds. Really I do. I debated long and hard if I should even have come.",portrait:"portraits/investigator.png"},{speaker:" ",text:"Lucas enters the house."},{speaker:"Lucas",text:"What... What's going on?",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:" ",text:"Lune runs up to him and hugs him tight, crying."},{speaker:"Rose",text:"It's Lune's... brother. This woman claims she spoke to him.",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"Oh no. No I didn't say I spoke to him, I..",portrait:"portraits/investigator.png"},{speaker:"Lucas",text:"You're a Sensitive? Wait... You're Delphine?",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"Delphine",text:"Yes. Do we know each other already?",portrait:"portraits/investigator.png"},{speaker:"Lucas",text:"Oh no. Not personally. But MI6 has employed you in the past. You've done some amazing work for us... and for the country. I thank you from the bottom of my heart.",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"Delphine",text:"Thank you. That means a lot.",portrait:"portraits/investigator.png"},{speaker:"Rose",text:"Wait. So everything she's telling us is true?",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Lucas",text:"After what I've seen and heard, I wouldn't doubt anything she says.",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:" ",text:"Lune gets over the initial shock and finally speaks up."},{speaker:"Lune",text:"So you're saying my brother cared so deeply about me that he couldn't let go until he found out the truth?",portrait:"portraits/lune_older.png"},{speaker:"Delphine",text:"Yes that's what I'm saying. And the moment he discovered you were alive, happy and living your life, the echo of the letter he had sent me just vanished and I felt him leave, finally at peace.",portrait:"portraits/investigator.png"},{speaker:" ",text:"The room is silent for an uncomfortably long time."},{speaker:"Rose",text:"Tea! Where are my manners, do you want some tea?",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"That would be wonderful.",portrait:"portraits/investigator.png"},{speaker:" ",text:"They all take a seat in the sitting room."},{speaker:"Delphine",text:"Did I? Did I make the right choice by coming here? Or should I have left you blissfully unaware?",portrait:"portraits/investigator.png"},{speaker:" ",text:"Lune wipes a tear from her eye. It's a tear of joy."},{speaker:"Lune",text:"You made the right choice, Delphine. It has given me some actual closure. Thank you.",portrait:"portraits/lune_older.png"},{speaker:"Delphine",text:"Oh and before I forget!",portrait:"portraits/investigator.png"},{speaker:" ",text:"Delphine grabs something from her pocket."},{speaker:"Delphine",text:"I went to see Miss Seville before coming here you see. Just to get a sense of whether I should or not, you know?",portrait:"portraits/investigator.png"},{speaker:"Lucas",text:"Oh is Cynthia in the country?",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"Delphine",text:"Yes but only for a short while and it's all very hush-hush. No-one should know where she is but you know, I have my ways.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Anyway, Lune. She wanted you to have this.",portrait:"portraits/investigator.png"},{speaker:" ",text:"Delphine hands over a single solitary red pearl to Lune."},{speaker:"Delphine",text:"'As a keepsake lest we forget' is what she said to me.",portrait:"portraits/investigator.png"},{speaker:" ",text:"Lune attaches the red pearl to the front of her necklace. A radiant smile on her face."},{speaker:" ",text:"The end. ",action:"credits"}]},ROOM_EPIPHANY:{title:"Echoes Complete",lines:[{speaker:"Delphine",text:"My instincts tell me I have uncovered everything there is to see in this location. The remaining hours hold no secrets.",portrait:"portraits/investigator.png"}]},BOAT_TUTORIAL:{title:"The Boathouse",lines:[{speaker:"Delphine",text:"So Jeremiah said Kanan was interrogating Lucas at the boathouse. I'm assuming that was in progress before Jeremiah made the call.",portrait:"portraits/investigator.png"},{speaker:" ",text:"If Delphine selects Lucas and Kanan and focuses at 15:00, she should uncover the echo of that interaction."},{speaker:" ",text:"The numbers in the red bubbles on the timeline are hints. They indicate how many clues to events you haven't discovered are in this scene."},{speaker:" ",text:"By discovering this interaction between Lucas and Kanan, you will have decreased the hint number in the study at 4pm from 2 to 1."}]},BOAT_TUTORIAL_EMPTY:{title:"The Boathouse",lines:[{speaker:"Delphine",text:"I don't have everything I need to uncover echoes here yet. I need to go through the guest list and figure out who some of them are.",portrait:"portraits/investigator.png"}]},TIDAK_APA:{title:"Tidak Apa",theme:"jargon",lines:[{speaker:"Delphine",text:"Tidak apa is Malay for 'it doesn't matter'.",portrait:"portraits/investigator.png"}]},CYNTHIA_JOURNEY:{title:"Cynthia's Journey",lines:[{speaker:"Delphine",text:"I wonder how Cynthia's journey went. I know my benefactor has no need nor want to have that information but Miss Seville could yet prove useful to me.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"I should probably check in on her. I'm sure I can sense her journey in my mind's eye if I concentrate.",portrait:"portraits/investigator.png"}]},MANIFEST:{lines:[{speaker:"Delphine",text:"There's photos of key personnel. I can gather from the resonance I feel which ones will be important. I'll add them to the case file.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"I can only feel them from 8:00 on the Wednesday morning. Their launch would have been too far from the plantation before then and anyway I wouldn't have known where in the sea it would have emerged from.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"It's also very clear they were all together on the shore at 8:00 and then spread out afterwards.",portrait:"portraits/investigator.png"}]},PEARL_2:{lines:[{speaker:"Delphine",text:"The owner of an item can be deceptive sometimes. The pearl should be owned by Bone or Jeremiah in theory but it was with Cynthia for so long it's imbued with her essence.",portrait:"portraits/investigator.png"}]},SAMPAN:{lines:[{speaker:"Delphine",text:"a local dugout canoe.",portrait:"portraits/investigator.png"}]},PARANG:{lines:[{speaker:"Delphine",text:"the quintessential tropical utility knife and weapon. It's designed specifically for the dense, woody vegetation of the primary jungle.",portrait:"portraits/investigator.png"}]},CHARLESBROOKE:{lines:[{speaker:"Delphine",text:"Charles Brooke. That name rings a bell. Where did I see it before? I'm sure I've seen it somewhere during my research on Borneo. Maybe in my glossary about the colonies?",portrait:"portraits/investigator.png"}]},WHITERAJAH:{lines:[{speaker:"Delphine",text:"Yes, there! It's the White Rajah! And I have a photo too, how convenient.",portrait:"portraits/investigator.png",trigger:"reveal:p21"}]},IBAN:{lines:[{speaker:"Delphine",text:"the Iban warriors were the most legendary and feared warriors in the Malay Archipelago.",portrait:"portraits/investigator.png"}]},DUSUN:{lines:[{speaker:"Delphine",text:"The Dusun people are the largest indigenous group in north Borneo, they're farmers and fierce hunters.",portrait:"portraits/investigator.png"}]},BATU:{title:"Batu Sapi",lines:[{speaker:"Delphine",text:"Batu Sapi is a coastal area in Sandaka renowned for a natural three-legged buffalo-shaped rock formation created by erosion. Located near the beach in Karamunting, this landmark is steeped in local legend where it is believed to be the transformed body of a heroic buffalo that fought a crocodile to save a local village. ",portrait:"portraits/investigator.png"}]},JUBILEE:{lines:[{speaker:"Delphine",text:"The Sandakan Jubilee Clock Tower was a historic landmark located in Sandakan. It survived the war but was demolished soon after when the town was rebuilt. ",portrait:"portraits/investigator.png"}]},CHINESETOWN:{lines:[{speaker:"Delphine",text:"Chinese Town was a bustling district of shophouses and markets where the local Chinese community conducted their businesses. ",portrait:"portraits/investigator.png"}]},BARRAGE_BALLOONS:{lines:[{speaker:"Delphine",text:"Barrage balloons were used to protect London from dive bombers. They were filled with hydrogen and were tethered to the ground with steel cables. They were designed to force the enemy planes to fly higher to reduce bombing accuracy.",portrait:"portraits/investigator.png"}]},MIND_EYE:{lines:[{speaker:"Delphine",text:"Something has stirred in my mind's eye. I should check it out.",portrait:"portraits/investigator.png"}]},CYNTHIA_ENDING:{lines:[{speaker:" ",text:" ",action:"credits"}]},POST_CREDITS:{lines:[{speaker:" ",text:"February 1964"},{speaker:" ",text:"There is a knock at the front door."},{speaker:"Delphine",text:"Who could that be?",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"I'm coming!",portrait:"portraits/investigator.png"},{speaker:"Cynthia",text:"Hello Delphine.",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:"Delphine",text:"Agent Seville? What brings you here?",portrait:"portraits/investigator.png"},{speaker:"Cynthia",text:"I am in danger and I don't know who to trust anymore. I need your help.",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:"Delphine",text:"What's wrong? What's going on?",portrait:"portraits/investigator.png"},{speaker:"Cynthia",text:"One of our best agents and a very dear friend of mine has disappeared.",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:"Cynthia",text:"The last time I spoke to him, he said he was onto something big but that he was being followed.",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:"Cynthia",text:"I'm worried sick but I fear the worst and that someone from the inside is responsible.",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:"Delphine",text:"I'm sorry to hear that. What was his name?",portrait:"portraits/investigator.png"},{speaker:"Cynthia",text:"His name is Arthur. Arthur Birdwhistle.",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:" ",text:" ",action:"tbc"}]},TOO_SOON:{title:"Trail Interrupted",lines:[{speaker:"Delphine",text:" I don't have enough information to identify the soldiers or follow the trail past this hour yet. I need to unlock some more memories first. I should come back later.",portrait:"portraits/investigator.png"}]}};export{t as DIALOGUE};
